using System;using System.Windows;using System.Windows.Controls;using System.Windows.Media;
namespace Tgirrr.CadLisp { public sealed class DripLayoutWindow:Window {static double lastInset=0.5,lastSpacing=0.4;readonly TextBox inset=Input(lastInset),spacing=Input(lastSpacing);internal double Inset,Spacing;public DripLayoutWindow(){Title="TGIRR — Rải dây nhỏ giọt";Width=500;Height=290;MinWidth=460;MinHeight=270;SizeToContent=SizeToContent.Manual;WindowStartupLocation=WindowStartupLocation.CenterScreen;ResizeMode=ResizeMode.CanResizeWithGrip;Background=new SolidColorBrush(Color.FromRgb(36,45,57));Foreground=Brushes.White;FontFamily=new FontFamily("Segoe UI");var root=new Grid{Margin=new Thickness(18)};root.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});root.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});root.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});root.RowDefinitions.Add(new RowDefinition());root.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});Content=root;var title=new TextBlock{Text="RẢI DÂY NHỎ GIỌT",FontSize=16,FontWeight=FontWeights.SemiBold,Foreground=new SolidColorBrush(Color.FromRgb(202,139,67)),Margin=new Thickness(0,0,0,12)};Grid.SetRow(title,0);root.Children.Add(title);var fields=new Grid{Margin=new Thickness(0,0,0,8)};fields.ColumnDefinitions.Add(new ColumnDefinition());fields.ColumnDefinitions.Add(new ColumnDefinition());Grid.SetRow(fields,1);root.Children.Add(fields);AddField(fields,0,"Khoảng lùi từ biên",inset);AddField(fields,1,"Khoảng cách giữa các dây",spacing);var note=new Border{Background=new SolidColorBrush(Color.FromRgb(29,39,51)),CornerRadius=new CornerRadius(4),Padding=new Thickness(10,8,10,8),Margin=new Thickness(0,2,0,8),Child=new TextBlock{Text="Hướng dây được lấy theo cạnh dài nhất của từng Boundary. Đường offset phía trong được giữ lại để nối các đầu dây.",TextWrapping=TextWrapping.Wrap,Foreground=new SolidColorBrush(Color.FromRgb(171,190,207))}};Grid.SetRow(note,2);root.Children.Add(note);var buttons=new StackPanel{Orientation=Orientation.Horizontal,HorizontalAlignment=HorizontalAlignment.Right,VerticalAlignment=VerticalAlignment.Bottom};Grid.SetRow(buttons,4);root.Children.Add(buttons);var cancel=new Button{Content="ĐÓNG",Width=82,Padding=new Thickness(8,7,8,7),Margin=new Thickness(0,0,8,0)};cancel.Click+=(s,e)=>Close();buttons.Children.Add(cancel);var run=new Button{Content="RẢI DÂY",Width=112,Padding=new Thickness(8,7,8,7),FontWeight=FontWeights.SemiBold,Background=new SolidColorBrush(Color.FromRgb(156,99,44)),Foreground=Brushes.White};run.Click+=(s,e)=>{if(double.TryParse(inset.Text,out Inset)&&Inset>=0&&double.TryParse(spacing.Text,out Spacing)&&Spacing>0){lastInset=Inset;lastSpacing=Spacing;DialogResult=true;Close();}else MessageBox.Show("Khoảng lùi phải không âm và khoảng cách dây phải lớn hơn 0.","VDNG",MessageBoxButton.OK,MessageBoxImage.Warning);};buttons.Children.Add(run);}static TextBox Input(double value)=>new TextBox{Text=value.ToString(),Padding=new Thickness(7,5,7,5),MinWidth=140};static void AddField(Grid grid,int column,string label,Control input){var panel=new StackPanel{Margin=new Thickness(column==0?0:7,0,column==0?7:0,0)};panel.Children.Add(new TextBlock{Text=label,Margin=new Thickness(0,0,0,3)});panel.Children.Add(input);Grid.SetColumn(panel,column);grid.Children.Add(panel);}}
}
